| MCP:hMvNoD | #!/usr/bin/env bash
| MCP:hMvNoD | set -euo pipefail
| MCP:hMvNoD | TARGET=${1:-http://host.docker.internal:8080}
| MCP:hMvNoD | case "$TARGET" in
| MCP:hMvNoD |   http://127.0.0.1:*|http://localhost:*|http://host.docker.internal:*) ;;
| MCP:hMvNoD |   *) echo "Refusing non-local target: $TARGET" >&2; exit 2 ;;
| MCP:hMvNoD | esac
| MCP:hMvNoD | docker run --rm -t -v "$(pwd):/zap/wrk" ghcr.io/zaproxy/zaproxy:stable zap-baseline.py -t "$TARGET" -c zap/baseline.conf -J reports/zap_baseline.json || true
